def run_lengths(nums: list[int]) -> list[tuple[int, int]]:
    """Run-length encode nums as (value, count) pairs."""
    out = []
    for n in nums:
        if out and out[-1][0] == n:
            out[-1] = (n, out[-1][1] + 1)
        else:
            out.append((n, 1))
    return out

