def pivot_counts(recs: list[dict]) -> dict[str, dict[str, int]]:
    """Pivot records into city -> {category -> count}, keys sorted."""
    cities = sorted({r["city"] for r in recs})
    cats = sorted({r["cat"] for r in recs})
    return {c: {k: sum(1 for r in recs if r["city"] == c and r["cat"] == k)
                for k in cats}
            for c in cities}

