def restock_report(items: list[dict]) -> tuple[dict[str, int], list[str]]:
    """Return (totals per category, sorted names with qty below 5)."""
    totals = {}
    for it in items:
        totals[it["cat"]] = totals.get(it["cat"], 0) + it["qty"]
    low = sorted(it["name"] for it in items if it["qty"] < 5)
    return (totals, low)

